insert into public.tracks (
  name,
  location,
  street_address,
  city,
  state,
  postal_code,
  country,
  surface,
  length,
  track_type_id,
  is_banked,
  is_system
)
select
  track_seed.name,
  track_seed.location,
  track_seed.street_address,
  track_seed.city,
  track_seed.state,
  track_seed.postal_code,
  track_seed.country,
  track_seed.surface,
  track_seed.length,
  track_types.id,
  false,
  true
from track_seed
left join all_track_types track_types
  on track_types.name = track_seed.track_type_name
where not exists (
  select 1
  from public.tracks existing
  where lower(existing.name) = lower(track_seed.name)
    and coalesce(existing.city, '') = coalesce(track_seed.city, '')
    and coalesce(existing.state, '') = coalesce(track_seed.state, '')
    and existing.is_system = true
);
